part 'profile_storage_provider.g.dart';

// A trick to make `sharedPreferencesProvider` just a `Provider`.
// See: https://zenn.dev/riscait/books/flutter-riverpod-practical-introduction-archive/viewer/v0-shared-preferences (in Japanese)
@Riverpod(keepAlive: true)
SharedPreferences sharedPreferences(Ref ref) => throw UnimplementedError();

@Riverpod(keepAlive: true)
ProfileStorage profileStorage(Ref ref) {
  final prefs = ref.watch(sharedPreferencesProvider);
  return ProfileStorageImpl(prefs);
}

